SELECT t.user_role_id, t.user_id, t.role_id, t.is_valid, r.role_id as r_role_id, r.role_name as r_role_name, r.is_valid as r_is_valid FROM `tb_user_role` t LEFT JOIN `tb_role` r ON r.role_id = t.role_id
